import React from 'react';
import PlantUpload from '../components/PlantUpload';
import { signOut } from 'firebase/auth';
import { auth } from '../firebase/firebaseConfig';

export default function Dashboard({ user, onLogout }) {
  return (
    <div className="min-h-screen bg-gradient-to-br from-green-500 to-green-700 py-8 px-4">
      <div className="max-w-md mx-auto">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-3xl font-bold text-white">Bienvenido, {user.email}</h1>
          <button onClick={() => { signOut(auth); onLogout(); }} className="bg-white/30 px-4 py-2 rounded-lg text-white hover:bg-white/50">Cerrar sesión</button>
        </div>
        <PlantUpload />
      </div>
    </div>
  );
}
